1	import type { ChannelOutboundAdapter, ChannelPollResult } from "../channels/plugins/types.js";
2	import type { OutboundDeliveryResult } from "../infra/outbound/deliver.js";
3	
4	export type { ChannelOutboundAdapter } from "../channels/plugins/types.js";
5	
6	export type ChannelSendRawResult = {
7	  ok: boolean;
8	  messageId?: string | null;
9	  error?: string | null;
10	};
11	
12	export function attachChannelToResult<T extends object>(channel: string, result: T) {
13	  return {
14	    channel,
15	    ...result,
16	  };
17	}
18	
19	export function attachChannelToResults<T extends object>(channel: string, results: readonly T[]) {
20	  return results.map((result) => attachChannelToResult(channel, result));
21	}
22	
23	export function createEmptyChannelResult(
24	  channel: string,
25	  result: Partial<Omit<OutboundDeliveryResult, "channel" | "messageId">> & {
26	    messageId?: string;
27	  } = {},
28	): OutboundDeliveryResult {
29	  return attachChannelToResult(channel, {
30	    messageId: "",
31	    ...result,
32	  });
33	}
34	
35	type MaybePromise<T> = T | Promise<T>;
36	type SendTextParams = Parameters<NonNullable<ChannelOutboundAdapter["sendText"]>>[0];
37	type SendMediaParams = Parameters<NonNullable<ChannelOutboundAdapter["sendMedia"]>>[0];
38	type SendPollParams = Parameters<NonNullable<ChannelOutboundAdapter["sendPoll"]>>[0];
39	
40	export function createAttachedChannelResultAdapter(params: {
41	  channel: string;
42	  sendText?: (ctx: SendTextParams) => MaybePromise<Omit<OutboundDeliveryResult, "channel">>;
43	  sendMedia?: (ctx: SendMediaParams) => MaybePromise<Omit<OutboundDeliveryResult, "channel">>;
44	  sendPoll?: (ctx: SendPollParams) => MaybePromise<Omit<ChannelPollResult, "channel">>;
45	}): Pick<ChannelOutboundAdapter, "sendText" | "sendMedia" | "sendPoll"> {
46	  return {
47	    sendText: params.sendText
48	      ? async (ctx) => attachChannelToResult(params.channel, await params.sendText!(ctx))
49	      : undefined,
50	    sendMedia: params.sendMedia
51	      ? async (ctx) => attachChannelToResult(params.channel, await params.sendMedia!(ctx))
52	      : undefined,
53	    sendPoll: params.sendPoll
54	      ? async (ctx) => attachChannelToResult(params.channel, await params.sendPoll!(ctx))
55	      : undefined,
56	  };
57	}
58	
59	export function createRawChannelSendResultAdapter(params: {
60	  channel: string;
61	  sendText?: (ctx: SendTextParams) => MaybePromise<ChannelSendRawResult>;
62	  sendMedia?: (ctx: SendMediaParams) => MaybePromise<ChannelSendRawResult>;
63	}): Pick<ChannelOutboundAdapter, "sendText" | "sendMedia"> {
64	  return {
65	    sendText: params.sendText
66	      ? async (ctx) => buildChannelSendResult(params.channel, await params.sendText!(ctx))
67	      : undefined,
68	    sendMedia: params.sendMedia
69	      ? async (ctx) => buildChannelSendResult(params.channel, await params.sendMedia!(ctx))
70	      : undefined,
71	  };
72	}
73	
74	/** Normalize raw channel send results into the shape shared outbound callers expect. */
