/** Credentials and connection info for a single PulseBoard account. */
export interface PulseBoardAccount {
  boardUrl: string;
  apiToken: string;
  username: string;
}

/** Top-level PulseBoard config: keyed map of named accounts. */
export interface PulseBoardConfig {
  accounts: Record<string, PulseBoardAccount>;
}

/** A single inbound or outbound PulseBoard message. */
export interface PulseBoardMessage {
  id: string;
  boardId: string;
  authorId: string;
  content: string;
  timestamp: number;
}

