import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";

/**
 * PulseBoard channel plugin — a fictional real-time bulletin board messenger.
 *
 * Adapters are intentionally stubbed; wire them up when a real PulseBoard SDK
 * becomes available.
 */
export const pulseBoardPlugin: ChannelPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    // Meta is defined inline because "pulseboard" is not registered in the
    // built-in channel registry (src/channels/ids.ts) and we must not modify
    // existing files.
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin board messaging via PulseBoard.",
      order: 200,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      listAccountIds: () => [],
      resolveAccount: () => ({ accountId: "default", configured: false }),
      resolveDefaultAccountId: () => "default",
      isConfigured: () => false,
      describeAccount: () => ({ accountId: "default", configured: false }),
    },
    setup: {
      applyAccountConfig: async () => {
        // Stub — will apply PulseBoard account credentials to the config file.
      },
    },
    messaging: {
      normalizeTarget: (target: string) => target.trim(),
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(
          `[${ctx.accountId}] PulseBoard provider connected (stub)`,
        );
        return {
          stop: () => {
            ctx.log?.info(`[${ctx.accountId}] PulseBoard provider stopped`);
          },
        };
      },
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to }) => {
      // Stub — deliver text to the PulseBoard API when available.
      return attachChannelToResult("pulseboard", {
        to,
        messageId: `pb-${Date.now()}`,
      });
    },
  },
});

